import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as r,f as a}from"./app-349d5105.js";const t="/assets/images/algorithm/1/自动转移过程.png",l={},n=a('<h1 id="有限状态自动机" tabindex="-1"><a class="header-anchor" href="#有限状态自动机" aria-hidden="true">#</a> 有限状态自动机</h1><p>确定有限状态自动机（以下简称「自动机」）是一类计算模型。它包含一系列状态，这些状态中：<br> 有一种特殊的状态，被称作「初始状态」。<br> 还有一系列状态被称为「接受状态」，它们组成了一个特殊的集合。其中，一个状态可能既是「初始状态」，也是「接受状态」。<br> 起初，这个自动机处于「初始状态」。随后，它顺序地读取字符串中的每一个字符，并根据当前状态和读入的字符，按照某个事先约定好的「转移规则」，从当前状态转移到下一个状态；当状态转移完成后，它就读取下一个字符。当字符串全部读取完毕后，如果自动机处于某个「接受状态」，则判定该字符串「被接受」；否则，判定该字符串「被拒绝」。</p><div class="hint-container tip"><p class="hint-container-title">提示</p><p>如果输入的过程中某一步转移失败了，即不存在对应的「转移规则」，此时计算将提前中止。在这种情况下我们也判定该字符串「被拒绝」。</p><p>一个自动机，总能够回答某种形式的「对于给定的输入字符串 S，判断其是否满足条件 P」的问题。在本题中，条件 P 即为「构成合法的表示数值的字符串」。</p><p>自动机驱动的编程，可以被看做一种暴力枚举方法的延伸：它穷尽了在任何一种情况下，对应任何的输入，需要做的事情。</p><p>自动机在计算机科学领域有着广泛的应用。在算法领域，它与大名鼎鼎的字符串查找算法「KMP」算法有着密切的关联；在工程领域，它是实现「正则表达式」的基础。</p></div><h2 id="剑指-offer-20-表示数值的字符串" tabindex="-1"><a class="header-anchor" href="#剑指-offer-20-表示数值的字符串" aria-hidden="true">#</a> 剑指 Offer 20. 表示数值的字符串</h2><p><strong>请实现一个函数用来判断字符串是否表示数值（包括整数和小数）。</strong></p><h3 id="问题描述" tabindex="-1"><a class="header-anchor" href="#问题描述" aria-hidden="true">#</a> 问题描述</h3><p>在 C++ 文档 中，描述了一个合法的数值字符串应当具有的格式。具体而言，它包含以下部分：</p><p>符号位，即 +、−两种符号<br> 整数部分，即由若干字符 0−9 组成的字符串<br> 小数点<br> 小数部分，其构成与整数部分相同<br> 指数部分，其中包含开头的字符 e（大写小写均可）、可选的符号位，和整数部分<br> 相比于 C++ 文档而言，本题还有一点额外的不同，即允许字符串首末两端有一些额外的空格。</p><p>在上面描述的五个部分中，每个部分都不是必需的，但也受一些额外规则的制约，如：</p><p>如果符号位存在，其后面必须跟着数字或小数点。<br> 小数点的前后两侧，至少有一侧是数字。</p><h3 id="思路与算法" tabindex="-1"><a class="header-anchor" href="#思路与算法" aria-hidden="true">#</a> 思路与算法</h3><p>根据上面的描述，现在可以定义自动机的「状态集合」了。那么怎么挖掘出所有可能的状态呢？一个常用的技巧是，用「当前处理到字符串的哪个部分」当作状态的表述。根据这一技巧，不难挖掘出所有状态：</p><ol><li>起始的空格</li><li>符号位</li><li>整数部分</li><li>左侧有整数的小数点</li><li>左侧无整数的小数点（根据前面的第二条额外规则，需要对左侧有无整数的两种小数点做区分）</li><li>小数部分</li><li>字符e</li><li>指数部分的符号位</li><li>指数部分的整数部分</li><li>末尾的空格<br> 下一步是找出「初始状态」和「接受状态」的集合。根据题意，「初始状态」应当为状态 1，而「接受状态」的集合则为状态 3、状态 4、状态 6、状态 9 以及状态 10。换言之，字符串的末尾要么是空格，要么是数字，要么是小数点，但前提是小数点的前面有数字。</li></ol><p>最后，需要定义「转移规则」。结合数值字符串应当具备的格式，将自动机转移的过程以图解的方式表示出来：<br><img src="'+t+'" alt="自动转移过程" loading="lazy"></p>',14),s=[n];function o(p,h){return e(),r("div",null,s)}const _=i(l,[["render",o],["__file","1.有限状态机.html.vue"]]);export{_ as default};
